void WavetableOscillator::extractFramesFromBuffer(const juce::AudioBuffer<float>& buffer, double bufferSr)
{
    if (sharedMode) return;
    const float* data = buffer.getReadPointer(0);
    const int totalSamples = buffer.getNumSamples();

    if (totalSamples < FRAME_SIZE) return;

    const int analysisLen = std::min(4096, totalSamples);
    float detectedPitch = detectPitch(data, analysisLen, bufferSr);

    std::vector<std::vector<float>> frames;

    if (detectedPitch > 20.0f && detectedPitch < 5000.0f)
    {
        double periodSamples = bufferSr / detectedPitch;
        int pos = 0;

        while (pos + static_cast<int>(periodSamples * 1.5) < totalSamples && static_cast<int>(frames.size()) < 256)
        {
            std::vector<float> frame(FRAME_SIZE);
            for (int i = 0; i < FRAME_SIZE; i++)
            {
                double srcPos = pos + (static_cast<double>(i) / FRAME_SIZE) * periodSamples;
                frame[i] = lanczosSample(data, totalSamples, srcPos);
            }

            float diff = frame[0] - frame[FRAME_SIZE - 1];
            for (int i = 0; i < FRAME_SIZE; i++)
                frame[i] += diff * static_cast<float>(i) / FRAME_SIZE;

            frames.push_back(std::move(frame));
            pos += static_cast<int>(periodSamples);
        }
    }
    else
    {
        const int hop = FRAME_SIZE / 2;
        int pos = 0;

        while (pos + FRAME_SIZE <= totalSamples && static_cast<int>(frames.size()) < 256)
        {
            std::vector<float> frame(FRAME_SIZE);
            for (int i = 0; i < FRAME_SIZE; i++)
            {
                float window = 0.5f * (1.0f - std::cos(2.0f * juce::MathConstants<float>::pi * i / FRAME_SIZE));
                frame[i] = data[pos + i] * window;
            }

            float diff = frame[0] - frame[FRAME_SIZE - 1];
            for (int i = 0; i < FRAME_SIZE; i++)
                frame[i] += diff * static_cast<float>(i) / FRAME_SIZE;

            frames.push_back(std::move(frame));
            pos += hop;
        }
    }

    while (static_cast<int>(frames.size()) < MIN_FRAMES && !frames.empty())
    {
        frames.push_back(frames.back());
    }

    if (!frames.empty())
        generateMipLevels(frames);
}

static float detectPitch(const float* data, int length, double sr)
{
    if (length < 256) return -1.0f;

    const int halfLen = length / 2;
    std::vector<float> diff(halfLen, 0.0f);

    // Difference function
    for (int tau = 1; tau < halfLen; tau++)
    {
        float sum = 0.0f;
        for (int i = 0; i < halfLen; i++)
        {
            float d = data[i] - data[i + tau];
            sum += d * d;
        }
        diff[tau] = sum;
    }

    // Cumulative mean normalized difference
    diff[0] = 1.0f;
    float running = 0.0f;
    for (int tau = 1; tau < halfLen; tau++)
    {
        running += diff[tau];
        diff[tau] = diff[tau] * tau / running;
    }

    // Absolute threshold (0.1)
    constexpr float threshold = 0.1f;
    int tauEstimate = -1;
    for (int tau = 2; tau < halfLen; tau++)
    {
        if (diff[tau] < threshold)
        {
            while (tau + 1 < halfLen && diff[tau + 1] < diff[tau])
                tau++;
            tauEstimate = tau;
            break;
        }
    }

    if (tauEstimate < 0) return -1.0f;

    // Parabolic interpolation
    float s0 = diff[std::max(0, tauEstimate - 1)];
    float s1 = diff[tauEstimate];
    float s2 = diff[std::min(halfLen - 1, tauEstimate + 1)];
    float refinedTau = tauEstimate + 0.5f * (s0 - s2) / (s0 - 2.0f * s1 + s2 + 1e-10f);

    return static_cast<float>(sr / refinedTau);
}

Original-Code (TypeScript):
function sendMipToWorklet(): void {
    if (!workletNode || mipFrames.length === 0) return
    workletNode.port.postMessage({ mipFrames })
}

async function loadFrames(buffer: AudioBuffer, startSample = 0, endSample = buffer.length): Promise<void> {
    const mono = bufferToMono(buffer, startSample, endSample)
    const { frames: extracted, medianPitchHz } = extractFrames(mono, buffer.sampleRate)
    frames = extracted
    mipFrames = generateMipLevels(frames)
    frameCount.value = frames.length
    hasFrames.value = true
    detectedPitch.value = medianPitchHz

    if (medianPitchHz > 0) {
      currentFrequency.value = medianPitchHz
      if (workletNode) {
        const freqParam = workletNode.parameters.get('frequency')
        if (freqParam) freqParam.value = medianPitchHz
      }
    }

    sendMipToWorklet()
}

function loadRawFrames(rawFrames: Float32Array[]): void {
    if (rawFrames.length === 0) return

    frames = rawFrames.map(f => {
      const resampled = f.length === FRAME_SIZE ? new Float32Array(f) : sincResample(f, FRAME_SIZE)
      makeLoopSafe(resampled)
      normalizeFrame(resampled)
      return resampled
    })

    while (frames.length < MIN_FRAMES) {
      frames.push(new Float32Array(frames[frames.length - 1]!))
    }

    mipFrames = generateMipLevels(frames)
    frameCount.value = frames.length
    hasFrames.value = true

    sendMipToWorklet()
}

function setContext(ac: AudioContext): void {
    if (ctx && ctx !== ac) {
      stop()
      workletReady = false
    }
    ctx = ac
    ensureWorklet(ac)
}

function ensureContext(): AudioContext {
    if (!ctx || ctx.state === 'closed') {
      ctx = new AudioContext()
      workletReady = false
    }
    if (ctx.state === 'suspended') ctx.resume()
    return ctx
}

async function ensureWorklet(ac: AudioContext): Promise<void> {
    if (workletReady) return
    await ac.audioWorklet.addModule(
      new URL('../audio/wavetable-processor.js', import.meta.url),
    )
    workletReady = true
}

async function start(): Promise<void> {
    if (isPlaying.value || starting) return
    starting = true
    const gen = stopGeneration
    try {
      const ac = ensureContext()
      await ensureWorklet(ac)

      if (gen !== stopGeneration) return

      if (workletNode) { workletNode.disconnect(); workletNode = null }
      if (gainNode) { gainNode.disconnect(); gainNode = null }

      workletNode = new AudioWorkletNode(ac, 'wavetable-processor', {
        numberOfInputs: 0,
        numberOfOutputs: 1,
        outputChannelCount: [1],
      })
      gainNode = ac.createGain()
      gainNode.gain.value = 0.5
      workletNode.connect(gainNode)
      gainNode.connect(destinationNode ?? ac.destination)

      if (mipFrames.length > 0) {
        workletNode.port.postMessage({ mipFrames })
      }

      const freqParam = workletNode.parameters.get('frequency')
      if (freqParam) freqParam.value = currentFrequency.value
      const scanParam = workletNode.parameters.get('scanPosition')
      if (scanParam) scanParam.value = lastScanPosition

      isPlaying.value = true

      if (pendingScan) {
        const { attack, decay, start: s, end: e } = pendingScan
        pendingScan = null
        scheduleScanRamp(attack, decay, s, e)
      }
    } finally {
      starting = false
    }
  }

function stop(): void {
    stopGeneration++
    pendingScan = null
    if (workletNode) {
      workletNode.disconnect()
      workletNode = null
    }
    if (gainNode) {
      gainNode.disconnect()
      gainNode = null
    }
    isPlaying.value = false
}

function setFrequency(hz: number): void {
    currentFrequency.value = Math.max(20, Math.min(20000, hz))
    if (workletNode) {
      const param = workletNode.parameters.get('frequency')
      if (param) param.value = currentFrequency.value
    }
}

function setFrequencyFromNote(midiNote: number): void {
    setFrequency(440 * Math.pow(2, (midiNote - 69) / 12))
}

function glideToNote(midiNote: number, timeMs: number): void {
    glideToFrequency(440 * Math.pow(2, (midiNote - 69) / 12), timeMs)
}

function glideToFrequency(hz: number, timeMs: number): void {
    currentFrequency.value = Math.max(20, Math.min(20000, hz))
    if (workletNode) {
      const param = workletNode.parameters.get('frequency')
      if (param) {
        const ac = ctx ?? ensureContext()
        const now = ac.currentTime
        param.setValueAtTime(param.value, now)
        param.linearRampToValueAtTime(currentFrequency.value, now + timeMs / 1000)
      }
    }
}

